reveal(StrictlyOrderedVec::valid);
if post1_self_.valid()
    && post2_self_.valid()
    && post1_self_@ == pre_self_@.insert(r1 as int, k)
    && post2_self_@ == pre_self_@.insert(r2 as int, k)
    && 0 <= r1 < post1_self_@.len()
    && 0 <= r2 < post2_self_@.len()
    && post1_self_@.len() == pre_self_@.len() + 1
    && post2_self_@.len() == pre_self_@.len() + 1
{
    // Unfolded valid() gives sortedness for pre and both posts.
    assert(sorted(pre_self_@));
    assert(sorted(post1_self_@));
    assert(sorted(post2_self_@));
    assert(sorted(pre_self_@.insert(r1 as int, k)));
    assert(sorted(pre_self_@.insert(r2 as int, k)));
    assert(0 <= (r1 as int) && (r1 as int) <= pre_self_@.len());
    assert(0 <= (r2 as int) && (r2 as int) <= pre_self_@.len());

    // The sorted insertion position for k into a sorted vector is unique.
    lemma_sorted_insert_unique_pos::<K>(pre_self_@, k, r1 as int, r2 as int);

    assert(r1 as int == r2 as int);
    assert(r1 == r2);
    // With r1 == r2, both views are pre@.insert(r1, k); transitive equality.
    assert(pre_self_@.insert(r1 as int, k) == pre_self_@.insert(r2 as int, k));
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);
}

