proof fn lemma_sorted_insert_contradiction<K: KeyTrait + VerusClone>(
    s: Seq<K>, k: K, lo: int, hi: int,
)
    requires
        sorted(s),
        0 <= lo,
        lo < hi,
        hi <= s.len(),
        sorted(s.insert(lo, k)),
        sorted(s.insert(hi, k)),
    ensures
        false,
{
    K::cmp_properties();
    s.insert_ensures(lo, k);
    s.insert_ensures(hi, k);

    assert(s.insert(lo, k).len() == s.len() + 1);
    assert(s.insert(hi, k).len() == s.len() + 1);
    assert(lo < s.len());
    assert(0 <= hi - 1);
    assert(hi - 1 < hi);
    assert(hi <= s.len());

    // Index facts for s.insert(lo, k):
    //   position lo holds k, position lo+1 holds s[lo].
    assert(s.insert(lo, k)[lo] == k);
    assert(s.insert(lo, k)[lo + 1] == s[lo]);

    // Sortedness of s.insert(lo, k) at (lo, lo+1) gives  k < s[lo].
    assert(0 <= lo && lo < lo + 1 && lo + 1 < s.insert(lo, k).len());
    assert(s.insert(lo, k)[lo].cmp_spec(s.insert(lo, k)[lo + 1]).lt());
    assert(k.cmp_spec(s[lo]).lt());

    // Index facts for s.insert(hi, k):
    //   position hi-1 holds s[hi-1], position hi holds k.
    assert(s.insert(hi, k)[hi - 1] == s[hi - 1]);
    assert(s.insert(hi, k)[hi] == k);

    // Sortedness of s.insert(hi, k) at (hi-1, hi) gives  s[hi-1] < k.
    assert(0 <= hi - 1 && hi - 1 < hi && hi < s.insert(hi, k).len());
    assert(s.insert(hi, k)[hi - 1].cmp_spec(s.insert(hi, k)[hi]).lt());
    assert(s[hi - 1].cmp_spec(k).lt());

    // Tie s[lo] to s[hi-1] via sortedness of s (or by equality when lo == hi-1).
    if lo < hi - 1 {
        assert(0 <= lo && lo < hi - 1 && hi - 1 < s.len());
        assert(s[lo].cmp_spec(s[hi - 1]).lt());
    } else {
        assert(lo == hi - 1);
        assert(s[lo] == s[hi - 1]);
    }

    // Transitivity (cmp_properties) gives  k < s[hi-1];
    // asymmetry then gives  s[hi-1] > k, contradicting s[hi-1] < k.
    assert(k.cmp_spec(s[hi - 1]).lt());
    assert(s[hi - 1].cmp_spec(k).gt());
    assert(s[hi - 1].cmp_spec(k).lt());
    assert(false);
}

proof fn lemma_sorted_insert_unique_pos<K: KeyTrait + VerusClone>(
    s: Seq<K>, k: K, r1: int, r2: int,
)
    requires
        sorted(s),
        0 <= r1 <= s.len(),
        0 <= r2 <= s.len(),
        sorted(s.insert(r1, k)),
        sorted(s.insert(r2, k)),
    ensures
        r1 == r2,
{
    if r1 < r2 {
        lemma_sorted_insert_contradiction::<K>(s, k, r1, r2);
    }
    if r2 < r1 {
        lemma_sorted_insert_contradiction::<K>(s, k, r2, r1);
    }
}
